/* ── Scene, Camera, Renderer ── */

const scene = new THREE.Scene();
scene.background = new THREE.Color(CONFIG.renderer.backgroundColor);

const frustum = CONFIG.camera.frustum;
let aspect = window.innerWidth / window.innerHeight;
const cam = new THREE.OrthographicCamera(
  -frustum * aspect,
  frustum * aspect,
  frustum,
  -frustum,
  CONFIG.camera.near,
  CONFIG.camera.far
);
cam.position.set(...CONFIG.camera.startPosition);
cam.lookAt(0, 0, 0);
cam.zoom = CONFIG.camera.zoom.initial;
cam.updateProjectionMatrix();

const renderer = new THREE.WebGLRenderer({ antialias: CONFIG.renderer.antialias });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, CONFIG.renderer.pixelRatioMax));
renderer.shadowMap.enabled = CONFIG.renderer.shadows.enabled;
renderer.shadowMap.type = CONFIG.renderer.shadows.type;
document.getElementById('wrap').appendChild(renderer.domElement);

const GAME = {
  scene,
  camera: cam,
  renderer,
  occludables: [],
  occlusionMeshes: [],
};

function registerOccludable(group) {
  group.userData.occludable = true;
  group.userData.occlusionMeshes = [];

  group.traverse(child => {
    if (!child.isMesh) return;
    if (child.material) {
      if (Array.isArray(child.material)) {
        child.material = child.material.map(material => material.clone());
      } else {
        child.material = child.material.clone();
      }
    }
    child.userData.occludableGroup = group;
    group.userData.occlusionMeshes.push(child);
    GAME.occlusionMeshes.push(child);
  });

  GAME.occludables.push(group);
}

/* ── Lighting ── */

const ambLight = new THREE.AmbientLight(
  CONFIG.renderer.ambient.color,
  CONFIG.renderer.ambient.intensity
);
scene.add(ambLight);

const dirLight = new THREE.DirectionalLight(
  CONFIG.renderer.directional.color,
  CONFIG.renderer.directional.intensity
);
dirLight.position.set(...CONFIG.renderer.directional.startPosition);
dirLight.castShadow = true;
dirLight.shadow.mapSize.set(CONFIG.renderer.shadows.mapSize, CONFIG.renderer.shadows.mapSize);
dirLight.shadow.camera.left = -CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.right = CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.top = CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.bottom = -CONFIG.renderer.shadows.cameraBounds;
dirLight.shadow.camera.near = CONFIG.renderer.shadows.near;
dirLight.shadow.camera.far = CONFIG.renderer.shadows.far;
scene.add(dirLight);


/* ── Input ── */

const keys = {};
document.addEventListener('keydown', e => {
  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
  keys[e.code] = true;
  if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.code)) e.preventDefault();
});
document.addEventListener('keyup', e => { keys[e.code] = false; });
document.addEventListener('contextmenu', e => e.preventDefault());

// Clear all keys when window loses focus
function clearKeys() { for (const k in keys) delete keys[k]; }
window.addEventListener('blur', clearKeys);
window.addEventListener('focus', clearKeys);
document.addEventListener('visibilitychange', () => { if (document.hidden) clearKeys(); });


/* ── Audio ── */

const AUDIO_CFG = CONFIG.audio;
const AUDIO = {
  context: null,
  masterGain: null,
  ambientGain: null,
  sfxGain: null,
  enabled: AUDIO_CFG.enabled,
  unlocked: false,
  ambientStarted: false,
  ambientIndex: -1,
  ambientBuffers: [],
  ambientLoadPromise: null,
  ambientSlots: [],
  ambientSlotIndex: 0,
  ambientScheduleTimer: null,
  ambientRetryTimer: null,
  footstepBuffers: [],
  footstepLoadPromise: null,
  footstepDistance: 0,
  lastPlayerX: CONFIG.player.spawn.x,
  lastPlayerY: CONFIG.player.spawn.y,
  lastFootstepIndex: -1,
  recentFootstepIndexes: [],
  volumes: {
    master: AUDIO_CFG.defaults.masterVolume,
    ambient: AUDIO_CFG.defaults.ambientVolume,
    sfx: AUDIO_CFG.defaults.sfxVolume,
  },
  muted: AUDIO_CFG.defaults.muted,
};

function clampAudioVolume(value, fallback) {
  const normalized = Number.parseFloat(value);
  if (!Number.isFinite(normalized)) return fallback;
  return Math.max(0, Math.min(1, normalized));
}

function loadAudioPreferences() {
  AUDIO.volumes.master = clampAudioVolume(
    localStorage.getItem(AUDIO_CFG.storageKeys.masterVolume),
    AUDIO_CFG.defaults.masterVolume
  );
  AUDIO.volumes.ambient = clampAudioVolume(
    localStorage.getItem(AUDIO_CFG.storageKeys.ambientVolume),
    AUDIO_CFG.defaults.ambientVolume
  );
  AUDIO.volumes.sfx = clampAudioVolume(
    localStorage.getItem(AUDIO_CFG.storageKeys.sfxVolume),
    AUDIO_CFG.defaults.sfxVolume
  );
  AUDIO.muted = localStorage.getItem(AUDIO_CFG.storageKeys.muted) === 'true';
}

function updateAudioBusVolumes() {
  if (!AUDIO.masterGain || !AUDIO.ambientGain || !AUDIO.sfxGain) return;

  const master = AUDIO.muted ? 0 : AUDIO.volumes.master;
  AUDIO.masterGain.gain.value = master;
  AUDIO.ambientGain.gain.value = AUDIO.volumes.ambient;
  AUDIO.sfxGain.gain.value = AUDIO.volumes.sfx;
}

function ensureAudioContext() {
  if (!AUDIO.enabled) return null;
  if (AUDIO.context) return AUDIO.context;

  const AudioContextClass = window.AudioContext || window.webkitAudioContext;
  if (!AudioContextClass) {
    AUDIO.enabled = false;
    return null;
  }

  AUDIO.context = new AudioContextClass();
  AUDIO.masterGain = AUDIO.context.createGain();
  AUDIO.ambientGain = AUDIO.context.createGain();
  AUDIO.sfxGain = AUDIO.context.createGain();

  AUDIO.ambientGain.connect(AUDIO.masterGain);
  AUDIO.sfxGain.connect(AUDIO.masterGain);
  AUDIO.masterGain.connect(AUDIO.context.destination);
  updateAudioBusVolumes();

  return AUDIO.context;
}

function clearAmbientRetry() {
  if (!AUDIO.ambientRetryTimer) return;
  clearTimeout(AUDIO.ambientRetryTimer);
  AUDIO.ambientRetryTimer = null;
}

function clearAmbientSchedule() {
  if (!AUDIO.ambientScheduleTimer) return;
  clearTimeout(AUDIO.ambientScheduleTimer);
  AUDIO.ambientScheduleTimer = null;
}

function scheduleAmbientRetry() {
  clearAmbientRetry();
  AUDIO.ambientRetryTimer = setTimeout(() => {
    AUDIO.ambientRetryTimer = null;
    startAmbientLoop();
  }, AUDIO_CFG.ambient.retryDelayMs);
}

function decodeAudioBuffer(arrayBuffer) {
  const context = ensureAudioContext();
  if (!context) return Promise.resolve(null);

  return context.decodeAudioData(arrayBuffer.slice(0))
    .catch(() => null);
}

function preloadAmbient() {
  if (!AUDIO.enabled || AUDIO.ambientLoadPromise) return AUDIO.ambientLoadPromise;

  AUDIO.ambientLoadPromise = Promise.all(
    AUDIO_CFG.ambient.files.map(async file => {
      try {
        const response = await fetch(`${AUDIO_CFG.ambient.basePath}/${file}`);
        if (!response.ok) return null;
        const buffer = await response.arrayBuffer();
        return decodeAudioBuffer(buffer);
      } catch (error) {
        return null;
      }
    })
  ).then(buffers => {
    AUDIO.ambientBuffers = buffers.filter(Boolean);
    return AUDIO.ambientBuffers;
  });

  return AUDIO.ambientLoadPromise;
}

function preloadFootsteps() {
  if (!AUDIO.enabled || AUDIO.footstepLoadPromise) return AUDIO.footstepLoadPromise;

  AUDIO.footstepLoadPromise = Promise.all(
    AUDIO_CFG.footsteps.files.map(async file => {
      try {
        const response = await fetch(`${AUDIO_CFG.footsteps.basePath}/${file}`);
        if (!response.ok) return null;
        const buffer = await response.arrayBuffer();
        return decodeAudioBuffer(buffer);
      } catch (error) {
        return null;
      }
    })
  ).then(buffers => {
    AUDIO.footstepBuffers = buffers.filter(Boolean);
    return AUDIO.footstepBuffers;
  });

  return AUDIO.footstepLoadPromise;
}

function getNextAmbientTrackIndex() {
  const total = AUDIO.ambientBuffers.length;
  if (total === 0) return -1;
  if (total === 1) return 0;

  let nextIndex = Math.floor(Math.random() * total);
  if (nextIndex === AUDIO.ambientIndex) {
    nextIndex = (nextIndex + 1 + Math.floor(Math.random() * (total - 1))) % total;
  }
  return nextIndex;
}

function getAmbientTargetVolume() {
  return AUDIO.muted ? 0 : 1;
}

function fadeGainNode(gainNode, fromValue, toValue, durationSeconds) {
  const context = ensureAudioContext();
  if (!context || !gainNode) return;

  const now = context.currentTime;
  gainNode.gain.cancelScheduledValues(now);
  gainNode.gain.setValueAtTime(fromValue, now);
  gainNode.gain.linearRampToValueAtTime(toValue, now + Math.max(0.01, durationSeconds));
}

function getAmbientSlot(index) {
  if (!AUDIO.ambientSlots[index]) {
    AUDIO.ambientSlots[index] = { source: null, gainNode: null, trackIndex: -1 };
  }
  return AUDIO.ambientSlots[index];
}

function cleanupAmbientSlot(slot) {
  if (!slot) return;
  if (slot.source) {
    try {
      slot.source.stop();
    } catch (error) {
      // Ignore stop errors for already-finished sources.
    }
    slot.source.disconnect();
  }
  if (slot.gainNode) {
    slot.gainNode.disconnect();
  }
  slot.source = null;
  slot.gainNode = null;
  slot.trackIndex = -1;
}

function scheduleNextAmbientCrossfade(buffer) {
  clearAmbientSchedule();

  const duration = buffer ? buffer.duration : 0;
  const crossfadeSeconds = Math.max(1, AUDIO_CFG.ambient.crossfadeSeconds);

  if (!duration) {
    scheduleAmbientRetry();
    return;
  }

  const delaySeconds = duration > crossfadeSeconds + 0.25
    ? duration - crossfadeSeconds
    : Math.max(0.25, duration * 0.5);

  AUDIO.ambientScheduleTimer = setTimeout(() => {
    AUDIO.ambientScheduleTimer = null;
    startAmbientLoop();
  }, delaySeconds * 1000);
}

function startAmbientLoop() {
  if (!AUDIO.enabled || !AUDIO.unlocked) return;

  const context = ensureAudioContext();
  if (!context) return;
  if (AUDIO.ambientBuffers.length === 0) {
    preloadAmbient().then(buffers => {
      if (buffers && buffers.length) startAmbientLoop();
    });
    return;
  }

  const nextIndex = getNextAmbientTrackIndex();
  if (nextIndex === -1) return;

  AUDIO.ambientIndex = nextIndex;
  const buffer = AUDIO.ambientBuffers[nextIndex];
  const nextSlotIndex = AUDIO.ambientSlotIndex;
  const prevSlotIndex = (nextSlotIndex + 1) % 2;
  const nextSlot = getAmbientSlot(nextSlotIndex);
  const prevSlot = getAmbientSlot(prevSlotIndex);
  cleanupAmbientSlot(nextSlot);

  const source = context.createBufferSource();
  const gainNode = context.createGain();
  source.buffer = buffer;
  source.connect(gainNode);
  gainNode.connect(AUDIO.ambientGain);
  gainNode.gain.value = 0;

  nextSlot.source = source;
  nextSlot.gainNode = gainNode;
  nextSlot.trackIndex = nextIndex;
  AUDIO.ambientSlotIndex = prevSlotIndex;

  source.onended = () => {
    if (nextSlot.source === source) {
      cleanupAmbientSlot(nextSlot);
    }
  };

  source.start();
  AUDIO.ambientStarted = true;
  fadeGainNode(gainNode, 0, getAmbientTargetVolume(), AUDIO_CFG.ambient.fadeInSeconds);
  scheduleNextAmbientCrossfade(buffer);

  if (prevSlot.gainNode) {
    fadeGainNode(
      prevSlot.gainNode,
      prevSlot.gainNode.gain.value,
      0,
      AUDIO_CFG.ambient.crossfadeSeconds
    );
    setTimeout(() => cleanupAmbientSlot(prevSlot), AUDIO_CFG.ambient.crossfadeSeconds * 1000 + 100);
  }
}

function unlockAudio() {
  const context = ensureAudioContext();
  if (!context) return Promise.resolve(false);

  loadAudioPreferences();
  updateAudioBusVolumes();
  AUDIO.unlocked = true;

  return context.resume()
    .then(() => Promise.all([preloadAmbient(), preloadFootsteps()]))
    .then(([ambientBuffers]) => {
      if (!AUDIO.ambientStarted && ambientBuffers && ambientBuffers.length) {
        startAmbientLoop();
      }
      return true;
    })
    .catch(() => false);
}

function randomBetween(min, max) {
  return min + Math.random() * (max - min);
}

function getNextFootstepIndex() {
  const total = AUDIO.footstepBuffers.length;
  if (total === 0) return -1;
  if (total === 1) return 0;

  const blockedIndexes = new Set(AUDIO.recentFootstepIndexes);
  let availableIndexes = [];

  for (let index = 0; index < total; index++) {
    if (!blockedIndexes.has(index)) {
      availableIndexes.push(index);
    }
  }

  if (availableIndexes.length === 0) {
    availableIndexes = Array.from({ length: total }, (_, index) => index)
      .filter(index => index !== AUDIO.lastFootstepIndex);
  }

  const nextIndex = availableIndexes[Math.floor(Math.random() * availableIndexes.length)];
  AUDIO.lastFootstepIndex = nextIndex;
  AUDIO.recentFootstepIndexes.push(nextIndex);

  const historySize = Math.max(1, AUDIO_CFG.footsteps.recentHistorySize || 1);
  while (AUDIO.recentFootstepIndexes.length > historySize) {
    AUDIO.recentFootstepIndexes.shift();
  }

  return nextIndex;
}

function playRandomFootstep(stepProfile) {
  if (!AUDIO.enabled || !AUDIO.unlocked || AUDIO.footstepBuffers.length === 0) return;
  const context = ensureAudioContext();
  if (!context) return;

  const nextIndex = getNextFootstepIndex();
  if (nextIndex === -1) return;

  const source = context.createBufferSource();
  source.buffer = AUDIO.footstepBuffers[nextIndex];
  source.playbackRate.value = randomBetween(stepProfile.rateMin, stepProfile.rateMax);

  const gain = context.createGain();
  gain.gain.value = stepProfile.baseVolume * randomBetween(
    1 - AUDIO_CFG.footsteps.volumeJitter,
    1 + AUDIO_CFG.footsteps.volumeJitter
  );

  source.connect(gain);
  gain.connect(AUDIO.sfxGain);
  source.start(0);
}

function resetFootstepTracking() {
  AUDIO.footstepDistance = 0;
  AUDIO.lastPlayerX = pl ? pl.x : CONFIG.player.spawn.x;
  AUDIO.lastPlayerY = pl ? pl.y : CONFIG.player.spawn.y;
  AUDIO.recentFootstepIndexes = [];
}

function getFootstepProfile() {
  if (pl.crouching) {
    return {
      distance: AUDIO_CFG.footsteps.crouchDistance,
      rateMin: AUDIO_CFG.footsteps.playbackRate.crouchMin,
      rateMax: AUDIO_CFG.footsteps.playbackRate.crouchMax,
      baseVolume: AUDIO_CFG.footsteps.volume.crouch,
    };
  }

  if (pl.running) {
    return {
      distance: AUDIO_CFG.footsteps.runDistance,
      rateMin: AUDIO_CFG.footsteps.playbackRate.runMin,
      rateMax: AUDIO_CFG.footsteps.playbackRate.runMax,
      baseVolume: AUDIO_CFG.footsteps.volume.run,
    };
  }

  return {
    distance: AUDIO_CFG.footsteps.walkDistance,
    rateMin: AUDIO_CFG.footsteps.playbackRate.walkMin,
    rateMax: AUDIO_CFG.footsteps.playbackRate.walkMax,
    baseVolume: AUDIO_CFG.footsteps.volume.walk,
  };
}

function updateFootstepAudio() {
  if (!AUDIO.enabled || !AUDIO.unlocked) return;

  const dx = pl.x - AUDIO.lastPlayerX;
  const dy = pl.y - AUDIO.lastPlayerY;
  AUDIO.lastPlayerX = pl.x;
  AUDIO.lastPlayerY = pl.y;

  if (!pl.moving || pl.speed <= MOVE_CFG.minSpeed) {
    AUDIO.footstepDistance = 0;
    return;
  }

  AUDIO.footstepDistance += Math.sqrt(dx * dx + dy * dy);
  const stepProfile = getFootstepProfile();
  const stepDistance = stepProfile.distance;

  while (AUDIO.footstepDistance >= stepDistance) {
    AUDIO.footstepDistance -= stepDistance;
    playRandomFootstep(stepProfile);
  }
}

function updateAudio() {
  updateFootstepAudio();
}

loadAudioPreferences();


/* ── World Data Generation ── */

function createSeededRandom(initialSeed) {
  let seed = initialSeed;

  return {
    setSeed(nextSeed) {
      seed = nextSeed;
    },
    next() {
      seed = (seed * 16807 + 0) % 2147483647;
      return (seed & 0x7fffffff) / 0x7fffffff;
    },
    int(min, max) {
      return min + Math.floor(this.next() * (max - min + 1));
    },
  };
}

function createWorldData() {
  const width = CONFIG.world.width;
  const height = CONFIG.world.height;
  const map = Array.from({ length: height }, () => new Array(width).fill(CONFIG.world.tiles.grass));
  const buildings = [];
  const buildingGroups = [];
  const buildingGroupMap = Array.from({ length: height }, () => new Array(width).fill(-1));
  const random = createSeededRandom(CONFIG.world.seeds.buildings);
  const roads = {
    rows: [...CONFIG.world.roadRows],
    cols: [...CONFIG.world.roadCols],
  };
  const generation = CONFIG.world.generation;
  const tiles = CONFIG.world.tiles;

  function fillRoads() {
    for (const row of roads.rows) {
      for (let c = 0; c < width; c++) {
        map[row][c] = tiles.road;
        map[row + 1][c] = tiles.road;
        if (row > 0 && map[row - 1][c] === tiles.grass) map[row - 1][c] = tiles.sidewalk;
        if (row + 2 < height && map[row + 2][c] === tiles.grass) map[row + 2][c] = tiles.sidewalk;
      }
    }

    for (const col of roads.cols) {
      for (let r = 0; r < height; r++) {
        map[r][col] = tiles.road;
        map[r][col + 1] = tiles.road;
        if (col > 0 && map[r][col - 1] === tiles.grass) map[r][col - 1] = tiles.sidewalk;
        if (col + 2 < width && map[r][col + 2] === tiles.grass) map[r][col + 2] = tiles.sidewalk;
      }
    }
  }

  function canPlace(r, c, w, d, margin) {
    for (let dr = -margin; dr < d + margin; dr++) {
      for (let dc = -margin; dc < w + margin; dc++) {
        const rr = r + dr;
        const cc = c + dc;
        if (rr < 0 || rr >= height || cc < 0 || cc >= width) return false;
        if (map[rr][cc] !== tiles.grass) return false;
      }
    }

    return true;
  }

  function placeBuilding(r, c, w, d) {
    for (let dr = 0; dr < d; dr++) {
      for (let dc = 0; dc < w; dc++) {
        map[r + dr][c + dc] = tiles.building;
      }
    }

    const building = { r, c, w, d };
    buildings.push(building);
    return building;
  }

  function addFence(br, bc, bw, bd, roadSide) {
    const pad = generation.fencePadding;
    const fTop = br - pad;
    const fBot = br + bd + pad - 1;
    const fLeft = bc - pad;
    const fRight = bc + bw + pad - 1;
    const gateC = bc + Math.floor(bw / 2);
    const gateR = br + Math.floor(bd / 2);

    for (let r = fTop; r <= fBot; r++) {
      for (let c = fLeft; c <= fRight; c++) {
        if (r < 0 || r >= height || c < 0 || c >= width) continue;
        if (map[r][c] !== tiles.grass) continue;

        const isEdge = r === fTop || r === fBot || c === fLeft || c === fRight;
        if (!isEdge) continue;

        let isGate = false;
        if (roadSide === 'bottom' && r === fBot && c === gateC) isGate = true;
        if (roadSide === 'top' && r === fTop && c === gateC) isGate = true;
        if (roadSide === 'right' && c === fRight && r === gateR) isGate = true;
        if (roadSide === 'left' && c === fLeft && r === gateR) isGate = true;

        map[r][c] = isGate ? tiles.gate : tiles.fence;
      }
    }
  }

  function placeBuildings() {
    const hBounds = [0, ...roads.rows.map(row => row - 1), height - 1];
    const vBounds = [0, ...roads.cols.map(col => col - 1), width - 1];

    for (let blockRow = 0; blockRow < hBounds.length - 1; blockRow++) {
      for (let blockCol = 0; blockCol < vBounds.length - 1; blockCol++) {
        const blockTop = hBounds[blockRow] + generation.blockInset;
        const blockBottom = hBounds[blockRow + 1] - generation.blockBottomInset;
        const blockLeft = vBounds[blockCol] + generation.blockInset;
        const blockRight = vBounds[blockCol + 1] - generation.blockBottomInset;
        const blockW = blockRight - blockLeft;
        const blockH = blockBottom - blockTop;

        if (blockW < generation.lotWidth || blockH < generation.lotDepth) continue;

        for (
          let col = blockLeft;
          col + 5 <= blockRight;
          col += generation.lotWidth + random.int(0, generation.lotJitterMax)
        ) {
          const bw = random.int(3, 5);
          const bd = random.int(3, 4);
          const br = blockTop + generation.yardSetback;
          const bc = col + random.int(0, 1);

          if (canPlace(br, bc, bw, bd, generation.yardSetback)) {
            const building = placeBuilding(br, bc, bw, bd);
            if (random.next() < generation.fenceChance) addFence(building.r, building.c, building.w, building.d, 'top');
          }
        }

        for (
          let col = blockLeft;
          col + 5 <= blockRight;
          col += generation.lotWidth + random.int(0, generation.lotJitterMax)
        ) {
          const bw = random.int(3, 5);
          const bd = random.int(3, 4);
          const br = blockBottom - generation.yardSetback - bd;
          const bc = col + random.int(0, 1);

          if (canPlace(br, bc, bw, bd, generation.yardSetback)) {
            const building = placeBuilding(br, bc, bw, bd);
            if (random.next() < generation.fenceChance) addFence(building.r, building.c, building.w, building.d, 'bottom');
          }
        }
      }
    }
  }

  function placeTrees() {
    random.setSeed(CONFIG.world.seeds.trees);

    for (let r = 1; r < height - 1; r += 2) {
      for (let c = 1; c < width - 1; c += 2) {
        if (map[r][c] !== tiles.grass) continue;
        if (random.next() >= generation.treeChance) continue;

        const tr = r + random.int(0, 1);
        const tc = c + random.int(0, 1);
        if (tr < height && tc < width && map[tr][tc] === tiles.grass) {
          map[tr][tc] = tiles.tree;
        }
      }
    }
  }

  function placeStructures() {
    random.setSeed(CONFIG.world.seeds.structures);

    for (let r = 2; r < height - 2; r += 3) {
      for (let c = 2; c < width - 2; c += 3) {
        if (map[r][c] !== tiles.grass) continue;
        if (random.next() < generation.structureChance) {
          map[r][c] = tiles.structure;
        }
      }
    }
  }

  function buildBuildingGroups() {
    let groupId = 0;

    for (let r = 0; r < height; r++) {
      for (let c = 0; c < width; c++) {
        if (map[r][c] !== tiles.building || buildingGroupMap[r][c] !== -1) continue;

        const cells = [];
        const queue = [{ r, c }];
        buildingGroupMap[r][c] = groupId;

        while (queue.length) {
          const current = queue.shift();
          cells.push(current);

          for (const [dr, dc] of [[0, 1], [0, -1], [1, 0], [-1, 0]]) {
            const nr = current.r + dr;
            const nc = current.c + dc;

            if (nr < 0 || nr >= height || nc < 0 || nc >= width) continue;
            if (map[nr][nc] !== tiles.building || buildingGroupMap[nr][nc] !== -1) continue;

            buildingGroupMap[nr][nc] = groupId;
            queue.push({ r: nr, c: nc });
          }
        }

        let minC = width;
        let maxC = 0;
        let minR = height;
        let maxR = 0;

        for (const cell of cells) {
          if (cell.c < minC) minC = cell.c;
          if (cell.c > maxC) maxC = cell.c;
          if (cell.r < minR) minR = cell.r;
          if (cell.r > maxR) maxR = cell.r;
        }

        const w = maxC - minC + 1;
        const d = maxR - minR + 1;
        const area = cells.length;
        const floors = area <= 6 ? (groupId % 3 === 0 ? 2 : 1) : (groupId % 2 === 0 ? 2 : 1);
        const floorH = 1.4 + (groupId % 3) * 0.15;

        buildingGroups.push({
          pal: CONFIG.world.buildingPalettes[groupId % CONFIG.world.buildingPalettes.length],
          h: floors * floorH,
          floors,
          floorH,
          roofType: groupId % 3,
          minC,
          maxC,
          minR,
          maxR,
          w,
          d,
          area,
          cells,
        });

        groupId++;
      }
    }
  }

  fillRoads();
  placeBuildings();
  placeTrees();
  placeStructures();
  buildBuildingGroups();

  return {
    width,
    height,
    map,
    roads,
    tiles,
    buildings,
    buildingGroups,
    buildingGroupMap,
    colliders: CONFIG.world.colliders,
  };
}

const WORLD = createWorldData();


/* ── World Helpers & Collision ── */

const MW = WORLD.width;
const MH = WORLD.height;
const MAP = WORLD.map;
const hRoads = WORLD.roads.rows;
const vRoads = WORLD.roads.cols;
const gInfo = WORLD.buildingGroups;
const COLLIDERS = WORLD.colliders;
const FENCE_COLLIDERS = [];

function worldXFromCol(col) {
  return col - MW / 2 + 0.5;
}

function worldZFromRow(row) {
  return row - MH / 2 + 0.5;
}

function getTileCenterHeight(tile) {
  if (tile === WORLD.tiles.road) return -0.015;
  if (tile === WORLD.tiles.sidewalk) return 0.035;
  return 0;
}

function getGroundHeightAt(tx, ty) {
  const c = Math.max(0, Math.min(MW - 1, Math.round(tx)));
  const r = Math.max(0, Math.min(MH - 1, Math.round(ty)));
  return getTileCenterHeight(MAP[r][c]);
}

function isFenceTile(tile) {
  return tile === WORLD.tiles.fence || tile === WORLD.tiles.gate;
}

function addFenceCollider(cx, cz, hw, hd) {
  FENCE_COLLIDERS.push({ cx, cz, hw, hd });
}

function hitsFenceCollider(tx, ty) {
  for (const collider of FENCE_COLLIDERS) {
    if (Math.abs(tx - collider.cx) < collider.hw && Math.abs(ty - collider.cz) < collider.hd) {
      return true;
    }
  }

  return false;
}

function isSolid(tx, ty) {
  const c = Math.round(tx);
  const r = Math.round(ty);

  if (c < 0 || c >= MW || r < 0 || r >= MH) return true;
  if (hitsFenceCollider(tx, ty)) return true;

  for (const [dc, dr] of [[0, 0], [1, 0], [-1, 0], [0, 1], [0, -1]]) {
    const nc = c + dc;
    const nr = r + dr;

    if (nc < 0 || nc >= MW || nr < 0 || nr >= MH) continue;

    const collider = COLLIDERS[MAP[nr][nc]];
    if (!collider) continue;
    if (isFenceTile(MAP[nr][nc])) continue;

    const dx = tx - nc;
    const dy = ty - nr;

    if (collider.shape === 'circle') {
      if (dx * dx + dy * dy < collider.radius * collider.radius) return true;
      continue;
    }

    if (Math.abs(dx) < collider.hw && Math.abs(dy) < collider.hd) return true;
  }

  return false;
}


/* ── Terrain (instanced for performance) ── */

const GRASS = CONFIG.terrain.grassColors;
const ASPHALT = CONFIG.terrain.asphaltColors;
const SIDEWALK = CONFIG.terrain.sidewalkColors;
const TERRAIN_TILE = WORLD.tiles;

const tileGeo = new THREE.BoxGeometry(1, 0.15, 1);
const dummy = new THREE.Object3D();

const colorBuckets = {};
for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  const t = MAP[r][c];
  let col;
  let yOff = -0.075;

  if (t === TERRAIN_TILE.road) {
    col = ASPHALT[(c + r * 3) % ASPHALT.length];
    yOff = -0.09;
  } else if (t === TERRAIN_TILE.sidewalk) {
    col = SIDEWALK[(c * 5 + r * 2) % SIDEWALK.length];
    yOff = -0.04;
  } else {
    col = GRASS[(c * 3 + r * 7 + c * r) % GRASS.length];
  }

  const key = col + '|' + yOff;
  if (!colorBuckets[key]) colorBuckets[key] = { col, yOff, tiles: [] };
  colorBuckets[key].tiles.push({ c, r });
}

for (const key in colorBuckets) {
  const bucket = colorBuckets[key];
  const mat = new THREE.MeshLambertMaterial({ color: bucket.col });
  const mesh = new THREE.InstancedMesh(tileGeo, mat, bucket.tiles.length);
  mesh.receiveShadow = true;

  for (let i = 0; i < bucket.tiles.length; i++) {
    const tile = bucket.tiles[i];
    dummy.position.set(worldXFromCol(tile.c), bucket.yOff, worldZFromRow(tile.r));
    dummy.updateMatrix();
    mesh.setMatrixAt(i, dummy.matrix);
  }

  mesh.instanceMatrix.needsUpdate = true;
  scene.add(mesh);
}

/* ── Road markings (center line) ── */
const markGeo = new THREE.PlaneGeometry(0.08, 0.6);
const markMat = new THREE.MeshBasicMaterial({ color: 0xCCCC88, transparent: true, opacity: 0.6 });

for (const row of hRoads) {
  for (let c = 0; c < MW; c += 2) {
    if (MAP[row][c] !== TERRAIN_TILE.road) continue;
    const mark = new THREE.Mesh(markGeo, markMat);
    mark.rotation.x = -Math.PI / 2;
    mark.rotation.z = Math.PI / 2;
    mark.position.set(worldXFromCol(c), -0.005, worldZFromRow(row) + 0.5);
    scene.add(mark);
  }
}

for (const col of vRoads) {
  for (let r = 0; r < MH; r += 2) {
    if (MAP[r][col] !== TERRAIN_TILE.road) continue;
    const mark = new THREE.Mesh(markGeo, markMat);
    mark.rotation.x = -Math.PI / 2;
    mark.position.set(worldXFromCol(col) + 0.5, -0.005, worldZFromRow(r));
    scene.add(mark);
  }
}

/* ── Curb edges ── */
const curbMat = new THREE.MeshLambertMaterial({ color: 0x888878 });

for (const row of hRoads) {
  for (let c = 0; c < MW; c++) {
    if (MAP[row][c] !== TERRAIN_TILE.road) continue;

    if (row > 0 && MAP[row - 1][c] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(1, 0.08, 0.06), curbMat);
      curb.position.set(worldXFromCol(c), 0.0, row - MH / 2);
      scene.add(curb);
    }

    if (row + 2 < MH && MAP[row + 2][c] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(1, 0.08, 0.06), curbMat);
      curb.position.set(worldXFromCol(c), 0.0, row + 2 - MH / 2);
      scene.add(curb);
    }
  }
}

for (const col of vRoads) {
  for (let r = 0; r < MH; r++) {
    if (MAP[r][col] !== TERRAIN_TILE.road) continue;

    if (col > 0 && MAP[r][col - 1] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.08, 1), curbMat);
      curb.position.set(col - MW / 2, 0.0, worldZFromRow(r));
      scene.add(curb);
    }

    if (col + 2 < MW && MAP[r][col + 2] === TERRAIN_TILE.sidewalk) {
      const curb = new THREE.Mesh(new THREE.BoxGeometry(0.06, 0.08, 1), curbMat);
      curb.position.set(col + 2 - MW / 2, 0.0, worldZFromRow(r));
      scene.add(curb);
    }
  }
}

/* ── Traffic signs — yield signs on secondary roads at intersections ── */

const signPoleMat = new THREE.MeshLambertMaterial({ color: 0x888888 });
const signPoleGeo = new THREE.CylinderGeometry(0.02, 0.02, 1.2, 6);
const signBorderMat = new THREE.MeshLambertMaterial({ color: 0xCC2222 });
const signInnerMat = new THREE.MeshLambertMaterial({ color: 0xFFFFFF });
const signBackMat = new THREE.MeshLambertMaterial({ color: 0x666666 });
const yieldOuterShape = new THREE.Shape();
yieldOuterShape.moveTo(0, -0.18);
yieldOuterShape.lineTo(0.16, 0.12);
yieldOuterShape.lineTo(-0.16, 0.12);
yieldOuterShape.lineTo(0, -0.18);

const yieldInnerShape = new THREE.Shape();
const yieldInset = 0.04;
yieldInnerShape.moveTo(0, -0.18 + yieldInset * 1.5);
yieldInnerShape.lineTo(0.16 - yieldInset, 0.12 - yieldInset);
yieldInnerShape.lineTo(-0.16 + yieldInset, 0.12 - yieldInset);
yieldInnerShape.lineTo(0, -0.18 + yieldInset * 1.5);

const signOuterGeo = new THREE.ShapeGeometry(yieldOuterShape);
const signInnerGeo = new THREE.ShapeGeometry(yieldInnerShape);

function addYieldSign(x, z, facingAngle) {
  const signGroup = new THREE.Group();

  const pole = new THREE.Mesh(signPoleGeo, signPoleMat);
  pole.position.set(x, 0.6, z);
  pole.castShadow = true;
  signGroup.add(pole);

  const signOuter = new THREE.Mesh(signOuterGeo, signBorderMat);
  signOuter.position.set(x, 1.15, z);
  signOuter.rotation.y = facingAngle;
  signGroup.add(signOuter);

  const signInner = new THREE.Mesh(signInnerGeo, signInnerMat);
  signInner.position.set(x, 1.15, z);
  signInner.rotation.y = facingAngle;
  signInner.translateZ(0.002);
  signGroup.add(signInner);

  const signBack = new THREE.Mesh(signOuterGeo, signBackMat);
  signBack.position.set(x, 1.15, z);
  signBack.rotation.y = facingAngle + Math.PI;
  signBack.translateZ(0.002);
  signGroup.add(signBack);

  scene.add(signGroup);
}

for (const row of hRoads) {
  for (const col of vRoads) {
    const hx = col - MW / 2;
    const hz = row - MH / 2;
    addYieldSign(hx + 2.8, hz - 1.2, 0);
    addYieldSign(hx - 0.8, hz + 3.2, Math.PI);
  }
}


/* ── Buildings ── */

const ROOF_COLORS = CONFIG.world.roofColors;
const SMALL_STRUCTURE_COLORS = CONFIG.world.smallStructureColors;
const BUILDING_TILE = WORLD.tiles;
const WINDOW_FRAME_MAT = new THREE.MeshLambertMaterial({ color: 0x303030, transparent: true });
const WINDOW_GLASS_MAT = new THREE.MeshBasicMaterial({ color: 0xC8D8E8, transparent: true, opacity: 0.45 });
const WINDOW_GLOW_MAT = new THREE.MeshBasicMaterial({ color: 0xffdc64, transparent: true, opacity: 0.2 });
const WINDOW_SILL_MAT = new THREE.MeshLambertMaterial({ color: 0x888880, transparent: true });
const WINDOW_SIZE = { width: 0.22, height: 0.32, frame: 0.03 };
const WINDOW_GEOMETRIES = {
  glass: new THREE.PlaneGeometry(WINDOW_SIZE.width, WINDOW_SIZE.height),
  glow: new THREE.PlaneGeometry(WINDOW_SIZE.width - 0.02, WINDOW_SIZE.height - 0.02),
  top: new THREE.BoxGeometry(WINDOW_SIZE.width + WINDOW_SIZE.frame * 2, WINDOW_SIZE.frame, 0.02),
  side: new THREE.BoxGeometry(WINDOW_SIZE.frame, WINDOW_SIZE.height, 0.02),
  crossV: new THREE.BoxGeometry(0.015, WINDOW_SIZE.height, 0.015),
  crossH: new THREE.BoxGeometry(WINDOW_SIZE.width, 0.015, 0.015),
  sill: new THREE.BoxGeometry(WINDOW_SIZE.width + WINDOW_SIZE.frame * 2 + 0.04, 0.025, 0.04),
};

function addWindow(group, x, y, z, rotY) {
  const winGroup = new THREE.Group();
  winGroup.position.set(x, y, z);
  winGroup.rotation.y = rotY;

  const glass = new THREE.Mesh(WINDOW_GEOMETRIES.glass, WINDOW_GLASS_MAT);
  glass.position.z = 0.001;
  winGroup.add(glass);

  const glow = new THREE.Mesh(WINDOW_GEOMETRIES.glow, WINDOW_GLOW_MAT);
  glow.position.z = 0.0005;
  winGroup.add(glow);

  const top = new THREE.Mesh(WINDOW_GEOMETRIES.top, WINDOW_FRAME_MAT);
  top.position.set(0, WINDOW_SIZE.height / 2 + WINDOW_SIZE.frame / 2, 0.005);
  winGroup.add(top);

  const bot = new THREE.Mesh(WINDOW_GEOMETRIES.top, WINDOW_FRAME_MAT);
  bot.position.set(0, -WINDOW_SIZE.height / 2 - WINDOW_SIZE.frame / 2, 0.005);
  winGroup.add(bot);

  const left = new THREE.Mesh(WINDOW_GEOMETRIES.side, WINDOW_FRAME_MAT);
  left.position.set(-WINDOW_SIZE.width / 2 - WINDOW_SIZE.frame / 2, 0, 0.005);
  winGroup.add(left);

  const right = new THREE.Mesh(WINDOW_GEOMETRIES.side, WINDOW_FRAME_MAT);
  right.position.set(WINDOW_SIZE.width / 2 + WINDOW_SIZE.frame / 2, 0, 0.005);
  winGroup.add(right);

  const crossV = new THREE.Mesh(WINDOW_GEOMETRIES.crossV, WINDOW_FRAME_MAT);
  crossV.position.z = 0.005;
  winGroup.add(crossV);

  const crossH = new THREE.Mesh(WINDOW_GEOMETRIES.crossH, WINDOW_FRAME_MAT);
  crossH.position.set(0, 0.02, 0.005);
  winGroup.add(crossH);

  const sill = new THREE.Mesh(WINDOW_GEOMETRIES.sill, WINDOW_SILL_MAT);
  sill.position.set(0, -WINDOW_SIZE.height / 2 - WINDOW_SIZE.frame, 0.015);
  winGroup.add(sill);

  group.add(winGroup);
}

function addGableRoof(group, cx, cz, bw, bd, h, roofCol) {
  const roofMat = new THREE.MeshLambertMaterial({ color: roofCol, transparent: true, side: THREE.DoubleSide });
  const overhang = 0.15;
  const ridgeAlongX = bw >= bd;
  const spanW = ridgeAlongX ? bd : bw;
  const spanL = ridgeAlongX ? bw : bd;
  const roofH = 0.4 + spanW * 0.15;
  const hw = spanW / 2 + overhang;
  const hl = spanL / 2 + overhang;
  const vertices = [];
  const indices = [];

  if (ridgeAlongX) {
    vertices.push(
      cx - hl, h, cz - hw,
      cx - hl, h, cz + hw,
      cx - hl, h + roofH, cz,
      cx + hl, h, cz - hw,
      cx + hl, h, cz + hw,
      cx + hl, h + roofH, cz
    );
  } else {
    vertices.push(
      cx - hw, h, cz - hl,
      cx + hw, h, cz - hl,
      cx, h + roofH, cz - hl,
      cx - hw, h, cz + hl,
      cx + hw, h, cz + hl,
      cx, h + roofH, cz + hl
    );
  }

  indices.push(0, 3, 5, 0, 5, 2);
  indices.push(1, 2, 5, 1, 5, 4);
  indices.push(0, 2, 1);
  indices.push(3, 4, 5);

  const roofGeo = new THREE.BufferGeometry();
  roofGeo.setAttribute('position', new THREE.Float32BufferAttribute(vertices, 3));
  roofGeo.setIndex(indices);
  roofGeo.computeVertexNormals();

  const roof = new THREE.Mesh(roofGeo, roofMat);
  roof.castShadow = true;
  roof.receiveShadow = true;
  group.add(roof);

  const ridgeGeo = new THREE.BoxGeometry(
    ridgeAlongX ? spanL + overhang * 2 : 0.06,
    0.04,
    ridgeAlongX ? 0.06 : spanL + overhang * 2
  );
  const ridge = new THREE.Mesh(ridgeGeo, new THREE.MeshLambertMaterial({ color: 0x444440, transparent: true }));
  ridge.position.set(cx, h + roofH, cz);
  group.add(ridge);
}

for (let i = 0; i < gInfo.length; i++) {
  const g = gInfo[i];
  const pal = g.pal;
  const h = g.h;
  const bw = g.w;
  const bd = g.d;
  const floors = g.floors;
  const floorH = g.floorH;
  const cx = worldXFromCol((g.minC + g.maxC) / 2);
  const cz = worldZFromRow((g.minR + g.maxR) / 2);
  const bldGroup = new THREE.Group();

  const topMat = new THREE.MeshLambertMaterial({ color: pal.t, transparent: true });
  const leftMat = new THREE.MeshLambertMaterial({ color: pal.l, transparent: true });
  const rightMat = new THREE.MeshLambertMaterial({ color: pal.r, transparent: true });
  const mats = [rightMat, leftMat, topMat, topMat, rightMat, leftMat];

  const bld = new THREE.Mesh(new THREE.BoxGeometry(bw - 0.05, h, bd - 0.05), mats);
  bld.position.set(cx, h / 2, cz);
  bld.castShadow = true;
  bld.receiveShadow = true;
  bldGroup.add(bld);

  if (floors === 2) {
    const sepMat = new THREE.MeshLambertMaterial({ color: pal.l, transparent: true });
    for (const side of [-1, 1]) {
      const sep = new THREE.Mesh(new THREE.BoxGeometry(0.02, 0.05, bd - 0.03), sepMat);
      sep.position.set(cx + side * (bw / 2 - 0.01), floorH, cz);
      bldGroup.add(sep);
    }
    for (const side of [-1, 1]) {
      const sep = new THREE.Mesh(new THREE.BoxGeometry(bw - 0.03, 0.05, 0.02), sepMat);
      sep.position.set(cx, floorH, cz + side * (bd / 2 - 0.01));
      bldGroup.add(sep);
    }
  }

  const roofCol = ROOF_COLORS[i % ROOF_COLORS.length];
  if (g.roofType === 1) {
    addGableRoof(bldGroup, cx, cz, bw, bd, h, roofCol);
  } else {
    const roofMat = new THREE.MeshLambertMaterial({ color: roofCol, transparent: true });
    const parMat = new THREE.MeshLambertMaterial({ color: 0x888880, transparent: true });
    const slab = new THREE.Mesh(new THREE.BoxGeometry(bw + 0.08, 0.06, bd + 0.08), roofMat);
    slab.position.set(cx, h + 0.03, cz);
    slab.castShadow = true;
    bldGroup.add(slab);

    const parH = 0.12;
    const parW = 0.06;
    const parFB = new THREE.BoxGeometry(bw + 0.08, parH, parW);
    const parLR = new THREE.BoxGeometry(parW, parH, bd + 0.08);
    for (const side of [-1, 1]) {
      const pf = new THREE.Mesh(parFB, parMat);
      pf.position.set(cx, h + 0.06 + parH / 2, cz + side * (bd / 2 + 0.04 - parW / 2));
      bldGroup.add(pf);

      const pl = new THREE.Mesh(parLR, parMat);
      pl.position.set(cx + side * (bw / 2 + 0.04 - parW / 2), h + 0.06 + parH / 2, cz);
      bldGroup.add(pl);
    }
  }

  for (let f = 0; f < floors; f++) {
    const winY = f * floorH + floorH * 0.55;
    const winCountZ = Math.max(1, Math.floor(bd / 1.2));
    const winSpacingZ = bd / (winCountZ + 1);

    for (let wi = 1; wi <= winCountZ; wi++) {
      const wz = worldZFromRow(g.minR) + wi * winSpacingZ - 0.5;
      for (const side of [-1, 1]) {
        addWindow(bldGroup, cx + side * (bw / 2), winY, wz, side > 0 ? Math.PI / 2 : -Math.PI / 2);
      }
    }

    const winCountX = Math.max(1, Math.floor(bw / 1.2));
    const winSpacingX = bw / (winCountX + 1);
    for (let wi = 1; wi <= winCountX; wi++) {
      const wx = worldXFromCol(g.minC) + wi * winSpacingX - 0.5;
      for (const side of [-1, 1]) {
        if (f === 0 && side === 1 && Math.abs(wx - cx) < 0.35) continue;
        addWindow(bldGroup, wx, winY, cz + side * (bd / 2), side > 0 ? 0 : Math.PI);
      }
    }
  }

  const doorH = Math.min(0.8, floorH * 0.6);
  const doorMat = new THREE.MeshLambertMaterial({ color: 0x3A2815, transparent: true });
  const door = new THREE.Mesh(new THREE.PlaneGeometry(0.35, doorH), doorMat);
  door.position.set(cx, doorH / 2, cz + bd / 2 + 0.001);
  bldGroup.add(door);

  const dfMat = new THREE.MeshLambertMaterial({ color: 0x2A1A10, transparent: true });
  const dfTop = new THREE.Mesh(new THREE.BoxGeometry(0.42, 0.035, 0.02), dfMat);
  dfTop.position.set(cx, doorH + 0.015, cz + bd / 2 + 0.005);
  bldGroup.add(dfTop);

  for (const side of [-1, 1]) {
    const dfSide = new THREE.Mesh(new THREE.BoxGeometry(0.03, doorH - 0.05, 0.02), dfMat);
    dfSide.position.set(cx + side * 0.19, (doorH - 0.05) / 2 + 0.05, cz + bd / 2 + 0.005);
    bldGroup.add(dfSide);
  }

  const foundMat = new THREE.MeshLambertMaterial({ color: 0x666660, transparent: true });
  const found = new THREE.Mesh(new THREE.BoxGeometry(bw + 0.02, 0.1, bd + 0.02), foundMat);
  found.position.set(cx, 0.05, cz);
  bldGroup.add(found);

  scene.add(bldGroup);
  registerOccludable(bldGroup);
}

/* ── Fences and gates (type 6, 7) ── */
const fenceMat = new THREE.MeshLambertMaterial({ color: 0x8B7355, transparent: true });
const fencePostGeo = new THREE.BoxGeometry(0.06, 0.6, 0.06);
const fenceRailGeo = new THREE.BoxGeometry(0.04, 0.04, 1);
const fenceRailGeoX = new THREE.BoxGeometry(1, 0.04, 0.04);
const wicketMat = new THREE.MeshLambertMaterial({ color: 0x6B5B45, transparent: true });
const wicketFrameMat = new THREE.MeshLambertMaterial({ color: 0x5A4A35, transparent: true });
const wicketBraceGeo = new THREE.BoxGeometry(0.04, 0.04, 0.78);
const wicketPostGeo = new THREE.BoxGeometry(0.05, 0.52, 0.05);
const wicketRailGeoX = new THREE.BoxGeometry(0.84, 0.04, 0.04);
const wicketRailGeoZ = new THREE.BoxGeometry(0.04, 0.04, 0.84);
const FENCE_COLLIDER_HALF_THICKNESS = 0.09;
const FENCE_POST_COLLIDER_HALF_SIZE = 0.08;

function addFencePost(group, x, z, height, material, geo = fencePostGeo) {
  const post = new THREE.Mesh(geo, material);
  post.position.set(x, height / 2, z);
  post.castShadow = true;
  group.add(post);
}

function addHorizontalFenceCollision(c, r) {
  addFenceCollider(c + 0.5, r, 0.5, FENCE_COLLIDER_HALF_THICKNESS);
}

function addVerticalFenceCollision(c, r) {
  addFenceCollider(c, r + 0.5, FENCE_COLLIDER_HALF_THICKNESS, 0.5);
}

function addFencePostCollision(c, r) {
  addFenceCollider(c, r, FENCE_POST_COLLIDER_HALF_SIZE, FENCE_POST_COLLIDER_HALF_SIZE);
}

function addHorizontalGate(group, fx, fz) {
  const postOffset = 0.46;

  addFencePost(group, fx - postOffset, fz, 0.52, wicketFrameMat, wicketPostGeo);
  addFencePost(group, fx + postOffset, fz, 0.52, wicketFrameMat, wicketPostGeo);

  for (const y of [0.18, 0.35]) {
    const rail = new THREE.Mesh(wicketRailGeoX, wicketMat);
    rail.position.set(fx, y, fz);
    group.add(rail);
  }

  const brace = new THREE.Mesh(wicketBraceGeo, wicketFrameMat);
  brace.position.set(fx, 0.265, fz);
  brace.rotation.x = Math.PI / 4;
  brace.rotation.y = Math.PI / 2;
  group.add(brace);
}

function addVerticalGate(group, fx, fz) {
  const postOffset = 0.46;

  addFencePost(group, fx, fz - postOffset, 0.52, wicketFrameMat, wicketPostGeo);
  addFencePost(group, fx, fz + postOffset, 0.52, wicketFrameMat, wicketPostGeo);

  for (const y of [0.18, 0.35]) {
    const rail = new THREE.Mesh(wicketRailGeoZ, wicketMat);
    rail.position.set(fx, y, fz);
    group.add(rail);
  }

  const brace = new THREE.Mesh(wicketBraceGeo, wicketFrameMat);
  brace.position.set(fx, 0.265, fz);
  brace.rotation.z = Math.PI / 4;
  group.add(brace);
}

for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  const t = MAP[r][c];
  if (!isFenceTile(t)) continue;

  const fx = worldXFromCol(c);
  const fz = worldZFromRow(r);
  const fGroup = new THREE.Group();
  const hasRightNeighbor = c + 1 < MW && isFenceTile(MAP[r][c + 1]);
  const hasBottomNeighbor = r + 1 < MH && isFenceTile(MAP[r + 1][c]);

  addFencePostCollision(c, r);

  if (t === BUILDING_TILE.fence) {
    addFencePost(fGroup, fx, fz, 0.6, fenceMat);

    if (hasRightNeighbor) {
      const railTop = new THREE.Mesh(fenceRailGeoX, fenceMat);
      railTop.position.set(fx + 0.5, 0.5, fz);
      fGroup.add(railTop);

      const railBot = new THREE.Mesh(fenceRailGeoX, fenceMat);
      railBot.position.set(fx + 0.5, 0.2, fz);
      fGroup.add(railBot);
      addHorizontalFenceCollision(c, r);
    }

    if (hasBottomNeighbor) {
      const railTop = new THREE.Mesh(fenceRailGeo, fenceMat);
      railTop.position.set(fx, 0.5, fz + 0.5);
      fGroup.add(railTop);

      const railBot = new THREE.Mesh(fenceRailGeo, fenceMat);
      railBot.position.set(fx, 0.2, fz + 0.5);
      fGroup.add(railBot);
      addVerticalFenceCollision(c, r);
    }
  } else {
    if (hasRightNeighbor && !hasBottomNeighbor) {
      addHorizontalGate(fGroup, fx + 0.5, fz);
      addHorizontalFenceCollision(c, r);
    } else if (hasBottomNeighbor && !hasRightNeighbor) {
      addVerticalGate(fGroup, fx, fz + 0.5);
      addVerticalFenceCollision(c, r);
    } else {
      addFencePost(fGroup, fx, fz, 0.52, wicketFrameMat, wicketPostGeo);
    }
  }

  scene.add(fGroup);
  registerOccludable(fGroup);
}

/* ── Small structures (type 3) ── */
for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  if (MAP[r][c] !== BUILDING_TILE.structure) continue;

  const sx = worldXFromCol(c);
  const sz = worldZFromRow(r);
  const sh = 0.35 + ((c * 7 + r * 3) % 5) * 0.06;
  const col = SMALL_STRUCTURE_COLORS[(c * 7 + r * 3) % SMALL_STRUCTURE_COLORS.length];
  const sGroup = new THREE.Group();
  const sMat = new THREE.MeshLambertMaterial({ color: col, transparent: true });
  const sMesh = new THREE.Mesh(new THREE.BoxGeometry(0.45, sh, 0.45), sMat);
  sMesh.position.set(sx, sh / 2, sz);
  sMesh.castShadow = true;
  sMesh.receiveShadow = true;
  sGroup.add(sMesh);
  scene.add(sGroup);
  registerOccludable(sGroup);
}


/* ── Trees ── */
/* Scale: 1 unit ≈ 2.5m, trees ~8-12m = ~3.5-5 units */

const trunkGeo = new THREE.CylinderGeometry(0.1, 0.15, 2.5, 6);
const trunkMat = new THREE.MeshLambertMaterial({ color: 0x5C3A1E, transparent: true });
const foliageLayers = [
  { y: 2.0, r: 1.1, color: 0x1A5C0A },
  { y: 2.5, r: 0.95, color: 0x236614 },
  { y: 3.0, r: 0.8, color: 0x2C7420 },
  { y: 3.5, r: 0.6, color: 0x358228 },
  { y: 3.9, r: 0.35, color: 0x3E9030 },
];
const foliageMeshes = foliageLayers.map(layer => ({
  y: layer.y,
  geometry: new THREE.SphereGeometry(layer.r, 8, 6),
  material: new THREE.MeshLambertMaterial({ color: layer.color, transparent: true }),
}));

for (let r = 0; r < MH; r++) for (let c = 0; c < MW; c++) {
  if (MAP[r][c] !== WORLD.tiles.tree) continue;

  const tx = worldXFromCol(c);
  const tz = worldZFromRow(r);
  const treeGroup = new THREE.Group();

  const trunk = new THREE.Mesh(trunkGeo, trunkMat);
  trunk.position.set(tx, 1.25, tz);
  trunk.castShadow = true;
  treeGroup.add(trunk);

  for (const layer of foliageMeshes) {
    const foliage = new THREE.Mesh(layer.geometry, layer.material);
    foliage.position.set(tx, layer.y, tz);
    foliage.castShadow = true;
    treeGroup.add(foliage);
  }

  scene.add(treeGroup);
  registerOccludable(treeGroup);
}


/* ── Player Mesh ── */
/* Shared rig factory for in-game player and start-screen preview. */

const playerScale = CONFIG.player.scale;
const PLAYER_STYLE_OPTIONS = CONFIG.ui.startScreen.appearance;
const PLAYER_STYLE_STATE = {
  hair: 0,
  shirt: 0,
  pants: 0,
  shoes: 0,
};
const PLAYER_STYLE_TARGETS = {
  hair: [],
  shirt: [],
  pants: [],
  shoes: [],
};

function registerStyleMaterial(part, material) {
  if (!PLAYER_STYLE_TARGETS[part]) return material;
  PLAYER_STYLE_TARGETS[part].push(material);
  return material;
}

function createStyleMaterial(part, fallbackColor) {
  const palette = PLAYER_STYLE_OPTIONS[part];
  const color = palette ? palette[PLAYER_STYLE_STATE[part]] : fallbackColor;
  return registerStyleMaterial(part, new THREE.MeshLambertMaterial({ color }));
}

function applyPlayerAppearance() {
  for (const part in PLAYER_STYLE_TARGETS) {
    const color = PLAYER_STYLE_OPTIONS[part][PLAYER_STYLE_STATE[part]];
    for (const material of PLAYER_STYLE_TARGETS[part]) {
      material.color.setHex(color);
    }
  }
}

function cyclePlayerAppearance(part, direction) {
  const palette = PLAYER_STYLE_OPTIONS[part];
  if (!palette || palette.length === 0) return PLAYER_STYLE_STATE[part];

  const total = palette.length;
  PLAYER_STYLE_STATE[part] = (PLAYER_STYLE_STATE[part] + direction + total) % total;
  applyPlayerAppearance();
  return PLAYER_STYLE_STATE[part];
}

function getPlayerAppearanceColor(part) {
  return PLAYER_STYLE_OPTIONS[part][PLAYER_STYLE_STATE[part]];
}

function createPlayerRig() {
  const group = new THREE.Group();

  const upperBody = new THREE.Group();
  upperBody.position.y = 0.46;
  group.add(upperBody);

  const torsoGeo = new THREE.BoxGeometry(0.3, 0.38, 0.16);
  const torso = new THREE.Mesh(torsoGeo, createStyleMaterial('shirt', 0x5A7044));
  torso.position.y = 0.23;
  torso.castShadow = true;
  upperBody.add(torso);

  const beltGeo = new THREE.BoxGeometry(0.32, 0.04, 0.17);
  const belt = new THREE.Mesh(beltGeo, new THREE.MeshLambertMaterial({ color: 0x3A2A1A }));
  belt.position.y = 0.02;
  upperBody.add(belt);

  const collarGeo = new THREE.BoxGeometry(0.22, 0.03, 0.18);
  const collar = new THREE.Mesh(collarGeo, createStyleMaterial('shirt', 0x4A6038));
  collar.position.y = 0.43;
  upperBody.add(collar);

  const shoulderGeo = new THREE.BoxGeometry(0.38, 0.06, 0.18);
  const shoulders = new THREE.Mesh(shoulderGeo, createStyleMaterial('shirt', 0x526840));
  shoulders.position.y = 0.40;
  shoulders.castShadow = true;
  upperBody.add(shoulders);

  const armGeo = new THREE.BoxGeometry(0.1, 0.34, 0.12);
  const handGeo = new THREE.SphereGeometry(0.04, 6, 6);
  const skinMat = new THREE.MeshLambertMaterial({ color: 0xC49A6C });

  const armPivotL = new THREE.Group();
  armPivotL.position.set(-0.2, 0.40, 0);
  upperBody.add(armPivotL);

  const armL = new THREE.Mesh(armGeo, createStyleMaterial('shirt', 0x526840));
  armL.position.y = -0.17;
  armL.castShadow = true;
  armPivotL.add(armL);

  const handL = new THREE.Mesh(handGeo, skinMat);
  handL.position.y = -0.36;
  armPivotL.add(handL);

  const armPivotR = new THREE.Group();
  armPivotR.position.set(0.2, 0.40, 0);
  upperBody.add(armPivotR);

  const armR = new THREE.Mesh(armGeo, createStyleMaterial('shirt', 0x526840));
  armR.position.y = -0.17;
  armR.castShadow = true;
  armPivotR.add(armR);

  const handR = new THREE.Mesh(handGeo, skinMat);
  handR.position.y = -0.36;
  armPivotR.add(handR);

  const neckGeo = new THREE.CylinderGeometry(0.055, 0.065, 0.06, 6);
  const neck = new THREE.Mesh(neckGeo, new THREE.MeshLambertMaterial({ color: 0xC49A6C }));
  neck.position.y = 0.47;
  upperBody.add(neck);

  const headGroup = new THREE.Group();
  headGroup.position.y = 0.62;
  upperBody.add(headGroup);

  const headGeo = new THREE.SphereGeometry(0.13, 8, 8);
  const headMat = new THREE.MeshLambertMaterial({ color: 0xC49A6C });
  const head = new THREE.Mesh(headGeo, headMat);
  head.scale.set(1, 1.05, 0.95);
  head.castShadow = true;
  headGroup.add(head);

  const hairTop = new THREE.Mesh(
    new THREE.BoxGeometry(0.24, 0.06, 0.22),
    createStyleMaterial('hair', 0x3A2A1A)
  );
  hairTop.position.y = 0.12;
  headGroup.add(hairTop);

  const hairBack = new THREE.Mesh(
    new THREE.BoxGeometry(0.24, 0.16, 0.04),
    createStyleMaterial('hair', 0x3A2A1A)
  );
  hairBack.position.set(0, 0.03, -0.1);
  headGroup.add(hairBack);

  const hairSideL = new THREE.Mesh(
    new THREE.BoxGeometry(0.03, 0.1, 0.18),
    createStyleMaterial('hair', 0x3A2A1A)
  );
  hairSideL.position.set(-0.12, 0.05, 0);
  headGroup.add(hairSideL);

  const hairSideR = new THREE.Mesh(
    new THREE.BoxGeometry(0.03, 0.1, 0.18),
    createStyleMaterial('hair', 0x3A2A1A)
  );
  hairSideR.position.set(0.12, 0.05, 0);
  headGroup.add(hairSideR);

  const eyeMat = new THREE.MeshBasicMaterial({ color: 0x2A2015 });
  const eyeL = new THREE.Mesh(new THREE.BoxGeometry(0.035, 0.025, 0.01), eyeMat);
  eyeL.position.set(-0.045, 0.01, 0.12);
  headGroup.add(eyeL);

  const eyeR = new THREE.Mesh(new THREE.BoxGeometry(0.035, 0.025, 0.01), eyeMat);
  eyeR.position.set(0.045, 0.01, 0.12);
  headGroup.add(eyeR);

  const nose = new THREE.Mesh(
    new THREE.BoxGeometry(0.03, 0.03, 0.02),
    new THREE.MeshLambertMaterial({ color: 0xB8896A })
  );
  nose.position.set(0, -0.02, 0.125);
  headGroup.add(nose);

  const mouth = new THREE.Mesh(
    new THREE.BoxGeometry(0.06, 0.01, 0.01),
    new THREE.MeshBasicMaterial({ color: 0x8A5A4A })
  );
  mouth.position.set(0, -0.055, 0.12);
  headGroup.add(mouth);

  const earMat = new THREE.MeshLambertMaterial({ color: 0xB88A60 });
  const earL = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.06, 0.05), earMat);
  earL.position.set(-0.125, 0, 0);
  headGroup.add(earL);

  const earR = new THREE.Mesh(new THREE.BoxGeometry(0.03, 0.06, 0.05), earMat);
  earR.position.set(0.125, 0, 0);
  headGroup.add(earR);

  const thighGeo = new THREE.BoxGeometry(0.13, 0.22, 0.14);
  const shinGeo = new THREE.BoxGeometry(0.12, 0.2, 0.13);
  const kneeCapGeo = new THREE.BoxGeometry(0.125, 0.05, 0.145);
  const ankleGeo = new THREE.BoxGeometry(0.115, 0.05, 0.12);
  const shoeGeo = new THREE.BoxGeometry(0.13, 0.08, 0.2);
  const soleGeo = new THREE.BoxGeometry(0.14, 0.025, 0.22);

  function createLeg(sideX) {
    const legPivot = new THREE.Group();
    legPivot.position.set(sideX, 0.46, 0);
    group.add(legPivot);

    const thigh = new THREE.Mesh(thighGeo, createStyleMaterial('pants', 0x3A4A5C));
    thigh.position.y = -0.11;
    thigh.castShadow = true;
    legPivot.add(thigh);

    const kneePivot = new THREE.Group();
    kneePivot.position.y = -0.22;
    legPivot.add(kneePivot);

    const kneeCap = new THREE.Mesh(kneeCapGeo, createStyleMaterial('pants', 0x3A4A5C));
    kneeCap.position.y = -0.01;
    kneeCap.castShadow = true;
    kneePivot.add(kneeCap);

    const shin = new THREE.Mesh(shinGeo, createStyleMaterial('pants', 0x3A4A5C));
    shin.position.y = -0.12;
    shin.castShadow = true;
    kneePivot.add(shin);

    const anklePivot = new THREE.Group();
    anklePivot.position.y = -0.22;
    kneePivot.add(anklePivot);

    const ankle = new THREE.Mesh(ankleGeo, createStyleMaterial('pants', 0x3A4A5C));
    ankle.position.y = 0.015;
    ankle.castShadow = true;
    anklePivot.add(ankle);

    const shoe = new THREE.Mesh(shoeGeo, createStyleMaterial('shoes', 0x2A2018));
    shoe.position.set(0, -0.03, 0.03);
    shoe.castShadow = true;
    anklePivot.add(shoe);

    const sole = new THREE.Mesh(soleGeo, createStyleMaterial('shoes', 0x16120f));
    sole.position.set(0, -0.07, 0.03);
    anklePivot.add(sole);

    return { legPivot, kneePivot, anklePivot };
  }

  const leftLeg = createLeg(-0.08);
  const rightLeg = createLeg(0.08);

  const shadowGeo = new THREE.CircleGeometry(0.18, 12);
  const shadowMesh = new THREE.Mesh(
    shadowGeo,
    new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.25 })
  );
  shadowMesh.rotation.x = -Math.PI / 2;
  shadowMesh.position.y = CONFIG.player.shadowLocalY;
  group.add(shadowMesh);

  group.scale.set(playerScale, playerScale, playerScale);

  return {
    group,
    upperBody,
    headGroup,
    armPivotL,
    armPivotR,
    legPivotL: leftLeg.legPivot,
    legPivotR: rightLeg.legPivot,
    kneePivotL: leftLeg.kneePivot,
    kneePivotR: rightLeg.kneePivot,
    anklePivotL: leftLeg.anklePivot,
    anklePivotR: rightLeg.anklePivot,
  };
}

const MAIN_PLAYER_RIG = createPlayerRig();
const playerGroup = MAIN_PLAYER_RIG.group;
const upperBody = MAIN_PLAYER_RIG.upperBody;
const headGroup = MAIN_PLAYER_RIG.headGroup;
const armPivotL = MAIN_PLAYER_RIG.armPivotL;
const armPivotR = MAIN_PLAYER_RIG.armPivotR;
const legPivotL = MAIN_PLAYER_RIG.legPivotL;
const legPivotR = MAIN_PLAYER_RIG.legPivotR;
const kneePivotL = MAIN_PLAYER_RIG.kneePivotL;
const kneePivotR = MAIN_PLAYER_RIG.kneePivotR;
const anklePivotL = MAIN_PLAYER_RIG.anklePivotL;
const anklePivotR = MAIN_PLAYER_RIG.anklePivotR;

scene.add(playerGroup);
applyPlayerAppearance();


/* ── Player Movement & Animation ── */

const MOVE_CFG = CONFIG.player.movement;
const ANIM_CFG = CONFIG.player.animation;
const WALK_SPEED = MOVE_CFG.walkSpeed;
const RUN_SPEED = MOVE_CFG.runSpeed;
const ACCEL = MOVE_CFG.accel;
const DECEL = MOVE_CFG.decel;

const pl = {
  x: CONFIG.player.spawn.x, y: CONFIG.player.spawn.y, angle: 0,
  walkTime: 0, speed: 0, targetSpeed: 0,
  moving: false, running: false,
  crouching: false,
  crouchBlend: 0,
  groundY: 0,
};

const ANIM = {
  walk: ANIM_CFG.walk,
  run: ANIM_CFG.run
};
let crouchTogglePressed = false;

function updatePlayerPos() {
  playerGroup.position.set(
    pl.x - MW / 2 + 0.5,
    CONFIG.player.groundOffset + pl.groundY,
    pl.y - MH / 2 + 0.5
  );
  playerGroup.rotation.y = pl.angle;
}
updatePlayerPos();

function lerpTo(current, target, rate, dt) {
  return current + (target - current) * Math.min(1, rate * dt);
}

function clamp01(value) {
  return Math.max(0, Math.min(1, value));
}

function gaitLift(phase) {
  return clamp01((-Math.sin(phase) + 1) * 0.5);
}

function gaitDrive(phase) {
  return Math.sin(phase);
}

function update(dt) {
  if (keys['KeyC'] && !crouchTogglePressed) {
    pl.crouching = !pl.crouching;
  }
  crouchTogglePressed = !!keys['KeyC'];

  let dx = 0, dz = 0;
  if (keys['ArrowLeft']  || keys['KeyA']) { dx--; dz++; }
  if (keys['ArrowRight'] || keys['KeyD']) { dx++; dz--; }
  if (keys['ArrowUp']    || keys['KeyW']) { dx--; dz--; }
  if (keys['ArrowDown']  || keys['KeyS']) { dx++; dz++; }

  pl.running = !pl.crouching && !!(keys['ShiftLeft'] || keys['ShiftRight']);
  pl.moving = dx !== 0 || dz !== 0;

  // ── Speed with acceleration/deceleration ──
  if (pl.moving) {
    pl.targetSpeed = pl.crouching
      ? MOVE_CFG.crouchSpeed
      : (pl.running ? RUN_SPEED : WALK_SPEED);
    pl.speed = lerpTo(pl.speed, pl.targetSpeed, ACCEL, dt);
  } else {
    pl.speed = lerpTo(pl.speed, 0, DECEL, dt);
    if (pl.speed < MOVE_CFG.minSpeed) pl.speed = 0;
  }

  // ── Movement ──
  if (pl.moving) {
    const len = Math.sqrt(dx * dx + dz * dz);
    dx = dx / len * pl.speed * dt;
    dz = dz / len * pl.speed * dt;

    const nx = pl.x + dx, ny = pl.y + dz;
    if (!isSolid(nx, pl.y)) pl.x = Math.max(0.5, Math.min(MW - 1.5, nx));
    if (!isSolid(pl.x, ny)) pl.y = Math.max(0.5, Math.min(MH - 1.5, ny));

    // Rotate toward movement direction
    const targetAngle = Math.atan2(dx, dz);
    let diff = targetAngle - pl.angle;
    while (diff > Math.PI) diff -= Math.PI * 2;
    while (diff < -Math.PI) diff += Math.PI * 2;
    pl.angle += diff * Math.min(1, MOVE_CFG.turnSpeed * dt);
  }

  pl.crouchBlend = lerpTo(
    pl.crouchBlend,
    pl.crouching ? 1 : 0,
    ANIM_CFG.crouch.blendRate,
    dt
  );

  const isRunAnim = pl.speed > WALK_SPEED * ANIM_CFG.runThreshold;
  const a = isRunAnim ? ANIM.run : ANIM.walk;

  const intensity = Math.min(1, pl.speed / WALK_SPEED);
  const movementHeadingX = pl.moving ? dx : 0;
  const movementHeadingZ = pl.moving ? dz : 0;

  if (pl.speed > MOVE_CFG.minSpeed) {
    pl.walkTime += dt * a.freq * (pl.speed / (isRunAnim ? RUN_SPEED : WALK_SPEED));
  }

  const phase = pl.walkTime;
  const sinP = Math.sin(phase);
  const sinDouble = Math.sin(phase * 2);
  const strafeAmount = Math.max(-1, Math.min(1, movementHeadingX * 1.8));
  const leftDrive = gaitDrive(phase);
  const rightDrive = gaitDrive(phase + Math.PI);
  const leftLift = gaitLift(phase);
  const rightLift = gaitLift(phase + Math.PI);
  const strideBlend = 0.72 + pl.crouchBlend * 0.18;

  const crouchLegBend = ANIM_CFG.crouch.legBend * pl.crouchBlend;
  const crouchKneeBend = ANIM_CFG.crouch.kneeBend * pl.crouchBlend;
  const crouchAnkleBend = ANIM_CFG.crouch.ankleBend * pl.crouchBlend;
  const crouchArmForward = ANIM_CFG.crouch.armForward * pl.crouchBlend;
  const crouchLean = ANIM_CFG.crouch.torsoLean * pl.crouchBlend;

  const leftStride = leftDrive * a.legAmp * intensity * strideBlend;
  const rightStride = rightDrive * a.legAmp * intensity * strideBlend;
  const leftStepSettle = Math.max(0, leftDrive) * a.stepSnap * intensity;
  const rightStepSettle = Math.max(0, rightDrive) * a.stepSnap * intensity;

  legPivotL.rotation.x = leftStride + leftStepSettle + crouchLegBend;
  legPivotR.rotation.x = rightStride + rightStepSettle + crouchLegBend;

  const armSwing = leftDrive * a.armAmp * intensity;
  armPivotL.rotation.x = -armSwing + crouchArmForward;
  armPivotR.rotation.x = armSwing + crouchArmForward;

  kneePivotL.rotation.x = leftLift * a.kneeAmp * intensity + crouchKneeBend;
  kneePivotR.rotation.x = rightLift * a.kneeAmp * intensity + crouchKneeBend;

  const leftFootLevel = -(legPivotL.rotation.x + kneePivotL.rotation.x) * a.ankleLevel;
  const rightFootLevel = -(legPivotR.rotation.x + kneePivotR.rotation.x) * a.ankleLevel;
  anklePivotL.rotation.x = leftFootLevel + (leftLift * a.ankleLift * intensity) + crouchAnkleBend;
  anklePivotR.rotation.x = rightFootLevel + (rightLift * a.ankleLift * intensity) + crouchAnkleBend;

  armPivotL.rotation.z = 0.08 * intensity + strafeAmount * 0.04 + pl.crouchBlend * 0.05;
  armPivotR.rotation.z = -0.08 * intensity + strafeAmount * 0.04 - pl.crouchBlend * 0.05;

  upperBody.position.y =
    ANIM_CFG.upperBodyY +
    (ANIM_CFG.crouch.upperBodyY - ANIM_CFG.upperBodyY) * pl.crouchBlend +
    Math.abs(sinP) * a.bob * intensity;
  headGroup.position.y =
    ANIM_CFG.headY +
    (ANIM_CFG.crouch.headY - ANIM_CFG.headY) * pl.crouchBlend +
    Math.abs(sinP) * a.headBob * intensity;

  const leanTarget = isRunAnim ? a.leanFwd * intensity : 0;
  upperBody.rotation.x = lerpTo(
    upperBody.rotation.x,
    leanTarget + crouchLean,
    ANIM_CFG.bodyReturnRate,
    dt
  );

  upperBody.rotation.y = lerpTo(
    upperBody.rotation.y,
    (-leftDrive * a.bodyYaw * intensity) + (pl.crouchBlend * ANIM_CFG.crouch.bodyYaw * strafeAmount),
    ANIM_CFG.bodyReturnRate,
    dt
  );
  upperBody.rotation.z = lerpTo(
    upperBody.rotation.z,
    (sinDouble * a.bodyRoll * intensity * 0.75) + (strafeAmount * a.strafeSway * intensity) + (pl.crouchBlend * ANIM_CFG.crouch.bodyRoll * strafeAmount),
    ANIM_CFG.bodyReturnRate,
    dt
  );

  headGroup.rotation.x = lerpTo(
    headGroup.rotation.x,
    (-Math.abs(sinP) * a.headBob * 0.45 * intensity) + (pl.crouchBlend * ANIM_CFG.crouch.headPitch),
    ANIM_CFG.bodyReturnRate,
    dt
  );
  headGroup.rotation.z = lerpTo(
    headGroup.rotation.z,
    (sinDouble * a.bodyRoll * 0.5 * intensity) + (pl.crouchBlend * ANIM_CFG.crouch.headRoll * strafeAmount),
    ANIM_CFG.bodyReturnRate,
    dt
  );

  legPivotL.position.z = -leftDrive * a.hipSwing * intensity;
  legPivotR.position.z = -rightDrive * a.hipSwing * intensity;
  legPivotL.position.x = -0.08 + (rightLift - leftLift) * 0.012 * intensity;
  legPivotR.position.x = 0.08 + (leftLift - rightLift) * 0.012 * intensity;

  if (pl.speed < MOVE_CFG.minSpeed) {
    legPivotL.rotation.x = lerpTo(legPivotL.rotation.x, crouchLegBend, ANIM_CFG.idleReturnRate, dt);
    legPivotR.rotation.x = lerpTo(legPivotR.rotation.x, crouchLegBend, ANIM_CFG.idleReturnRate, dt);
    kneePivotL.rotation.x = lerpTo(kneePivotL.rotation.x, crouchKneeBend, ANIM_CFG.idleReturnRate, dt);
    kneePivotR.rotation.x = lerpTo(kneePivotR.rotation.x, crouchKneeBend, ANIM_CFG.idleReturnRate, dt);
    anklePivotL.rotation.x = lerpTo(
      anklePivotL.rotation.x,
      (-(crouchLegBend + crouchKneeBend) * ANIM_CFG.walk.ankleLevel) + crouchAnkleBend,
      ANIM_CFG.idleReturnRate,
      dt
    );
    anklePivotR.rotation.x = lerpTo(
      anklePivotR.rotation.x,
      (-(crouchLegBend + crouchKneeBend) * ANIM_CFG.walk.ankleLevel) + crouchAnkleBend,
      ANIM_CFG.idleReturnRate,
      dt
    );
    armPivotL.rotation.x = lerpTo(armPivotL.rotation.x, crouchArmForward, ANIM_CFG.idleReturnRate, dt);
    armPivotR.rotation.x = lerpTo(armPivotR.rotation.x, crouchArmForward, ANIM_CFG.idleReturnRate, dt);
    armPivotL.rotation.z = lerpTo(armPivotL.rotation.z, pl.crouchBlend * 0.05, ANIM_CFG.idleReturnRate, dt);
    armPivotR.rotation.z = lerpTo(armPivotR.rotation.z, -pl.crouchBlend * 0.05, ANIM_CFG.idleReturnRate, dt);
    upperBody.rotation.x = lerpTo(upperBody.rotation.x, crouchLean, ANIM_CFG.bodyReturnRate, dt);
    upperBody.rotation.y = lerpTo(upperBody.rotation.y, 0, ANIM_CFG.bodyReturnRate, dt);
    upperBody.rotation.z = lerpTo(upperBody.rotation.z, 0, ANIM_CFG.bodyReturnRate, dt);
    headGroup.rotation.x = lerpTo(headGroup.rotation.x, pl.crouchBlend * ANIM_CFG.crouch.headPitch, ANIM_CFG.bodyReturnRate, dt);
    headGroup.rotation.z = lerpTo(headGroup.rotation.z, 0, ANIM_CFG.bodyReturnRate, dt);
    legPivotL.position.z = lerpTo(legPivotL.position.z, 0, ANIM_CFG.idleReturnRate, dt);
    legPivotR.position.z = lerpTo(legPivotR.position.z, 0, ANIM_CFG.idleReturnRate, dt);
    legPivotL.position.x = lerpTo(legPivotL.position.x, -0.08, ANIM_CFG.idleReturnRate, dt);
    legPivotR.position.x = lerpTo(legPivotR.position.x, 0.08, ANIM_CFG.idleReturnRate, dt);
  }

  pl.groundY = lerpTo(pl.groundY, getGroundHeightAt(pl.x, pl.y), 14, dt);
  updatePlayerPos();
}


/* ── Camera ── */

const camOffset = new THREE.Vector3(...CONFIG.camera.offset);
const lightOffset = new THREE.Vector3(...CONFIG.camera.lightOffset);
const camTarget = new THREE.Vector3();
const occPlayerPos = new THREE.Vector3();
const occDir = new THREE.Vector3();
const occNowBlocking = new Set();

function updateCamera() {
  camTarget.copy(playerGroup.position);
  cam.position.copy(camTarget).add(camOffset);
  cam.lookAt(camTarget);
  cam.updateProjectionMatrix();
  dirLight.position.copy(camTarget).add(lightOffset);
  dirLight.target.position.copy(camTarget);
  dirLight.target.updateMatrixWorld();

  updateOcclusion();
}

/* ── Zoom ── */

const ZOOM_MIN = CONFIG.camera.zoom.min;
const ZOOM_MAX = CONFIG.camera.zoom.max;
renderer.domElement.addEventListener('wheel', e => {
  e.preventDefault();
  cam.zoom *= e.deltaY > 0 ? CONFIG.camera.zoom.wheelStepOut : CONFIG.camera.zoom.wheelStepIn;
  cam.zoom = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, cam.zoom));
  cam.updateProjectionMatrix();
}, { passive: false });

/* ── Occlusion (PZ-style see-through) ── */

const occRaycaster = new THREE.Raycaster();
const occFadeSpeed = CONFIG.occlusion.fadeSpeed;
const occTargetAlpha = CONFIG.occlusion.targetAlpha;
let occFaded = new Set();

function setGroupOpacity(group, alpha) {
  for (const child of group.userData.occlusionMeshes || []) {
    if (!child.material) continue;
    const mats = Array.isArray(child.material) ? child.material : [child.material];
    for (const mat of mats) {
      mat.opacity = alpha;
      mat.depthWrite = alpha > 0.9;
    }
  }
}

function updateOcclusion() {
  occPlayerPos.copy(playerGroup.position);
  occPlayerPos.y += CONFIG.occlusion.playerHeightOffset;

  occDir.copy(occPlayerPos).sub(cam.position).normalize();
  const dist = cam.position.distanceTo(occPlayerPos);
  occRaycaster.set(cam.position, occDir);
  occRaycaster.far = dist;

  const hits = occRaycaster.intersectObjects(GAME.occlusionMeshes, false);

  occNowBlocking.clear();
  for (const hit of hits) {
    const group = hit.object.userData.occludableGroup;
    if (group) occNowBlocking.add(group);
  }

  for (const group of occFaded) {
    if (!occNowBlocking.has(group)) {
      group.userData.occAlpha = Math.min(1, (group.userData.occAlpha || 0.2) + occFadeSpeed * 0.016);
      setGroupOpacity(group, group.userData.occAlpha);
      if (group.userData.occAlpha >= 1) {
        setGroupOpacity(group, 1);
        occFaded.delete(group);
        delete group.userData.occAlpha;
      }
    }
  }

  for (const group of occNowBlocking) {
    occFaded.add(group);
    group.userData.occAlpha = Math.max(occTargetAlpha, (group.userData.occAlpha || 1) - occFadeSpeed * 0.016);
    setGroupOpacity(group, group.userData.occAlpha);
  }
}


/* ── Start Screen Experience ── */

const START_SCREEN_CFG = CONFIG.ui.startScreen;
const START_SCREEN_ANIM = START_SCREEN_CFG.animation;
const START_SCREEN = {
  initialized: false,
  previewScene: null,
  previewCamera: null,
  previewRenderer: null,
  previewRig: null,
  previewTime: 0,
  previewRoot: document.getElementById('loader-preview-stage'),
  music: null,
  musicStarted: false,
  musicUnlocked: false,
  musicDisabled: false,
  musicRequestId: 0,
  swatches: {},
  pointerTargetX: 0,
  pointerTargetY: 0,
  pointerX: 0,
  pointerY: 0,
  bodyLookX: 0,
  bodyLookY: 0,
};

function updateAppearanceUI() {
  for (const part in START_SCREEN.swatches) {
    START_SCREEN.swatches[part].style.background = `#${getPlayerAppearanceColor(part).toString(16).padStart(6, '0')}`;
  }
}

function cycleAppearanceFromControl(part, direction) {
  cyclePlayerAppearance(part, direction);
  updateAppearanceUI();
}

function bindAppearanceControls() {
  const buttons = document.querySelectorAll('[data-style-key][data-style-dir]');
  buttons.forEach(button => {
    button.addEventListener('click', () => {
      cycleAppearanceFromControl(
        button.getAttribute('data-style-key'),
        Number(button.getAttribute('data-style-dir'))
      );
    });
  });

  document.querySelectorAll('[data-style-swatch]').forEach(swatch => {
    START_SCREEN.swatches[swatch.getAttribute('data-style-swatch')] = swatch;
  });

  updateAppearanceUI();
}

function resizeStartScreenPreview() {
  if (!START_SCREEN.previewRenderer || !START_SCREEN.previewRoot) return;

  const bounds = START_SCREEN.previewRoot.getBoundingClientRect();
  const width = Math.max(240, Math.floor(bounds.width));
  const height = Math.max(300, Math.floor(bounds.height));
  START_SCREEN.previewRenderer.setSize(width, height, false);
  START_SCREEN.previewCamera.aspect = width / height;
  START_SCREEN.previewCamera.updateProjectionMatrix();
}

function bindStartScreenPointer() {
  document.addEventListener('pointermove', event => {
    const nx = (event.clientX / window.innerWidth) * 2 - 1;
    const ny = (event.clientY / window.innerHeight) * 2 - 1;
    START_SCREEN.pointerTargetX = Math.max(-1, Math.min(1, nx));
    START_SCREEN.pointerTargetY = Math.max(-1, Math.min(1, ny));
  });

  document.addEventListener('pointerleave', () => {
    START_SCREEN.pointerTargetX = 0;
    START_SCREEN.pointerTargetY = 0;
  });
}

function initStartScreenPreview() {
  if (!START_SCREEN.previewRoot || START_SCREEN.previewRenderer) return;

  const previewScene = new THREE.Scene();
  const previewCamera = new THREE.PerspectiveCamera(30, 1, 0.1, 50);
  previewCamera.position.set(0, 0.85, 3.6);
  previewCamera.lookAt(0, 0.95, 0);

  const previewRenderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
  previewRenderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  previewRenderer.domElement.className = 'loader-preview-canvas';
  START_SCREEN.previewRoot.appendChild(previewRenderer.domElement);

  const amb = new THREE.AmbientLight(0xf0eee4, 1.2);
  previewScene.add(amb);

  const keyLight = new THREE.DirectionalLight(0xfff3d6, 1.25);
  keyLight.position.set(3.5, 4.2, 2.4);
  previewScene.add(keyLight);

  const rimLight = new THREE.DirectionalLight(0x87b5ff, 0.65);
  rimLight.position.set(-2.2, 2.4, -3.1);
  previewScene.add(rimLight);

  const pedestal = new THREE.Mesh(
    new THREE.CylinderGeometry(1.02, 1.18, 0.28, 24),
    new THREE.MeshLambertMaterial({ color: 0x1f2a30 })
  );
  pedestal.position.y = -0.16;
  previewScene.add(pedestal);

  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.95, 0.045, 10, 40),
    new THREE.MeshBasicMaterial({ color: 0x8ee7c3, transparent: true, opacity: 0.3 })
  );
  ring.rotation.x = Math.PI / 2;
  ring.position.y = -0.005;
  previewScene.add(ring);

  const previewRig = createPlayerRig();
  previewRig.group.position.y = 0.12;
  previewRig.group.rotation.y = 0.52;
  previewScene.add(previewRig.group);

  START_SCREEN.previewScene = previewScene;
  START_SCREEN.previewCamera = previewCamera;
  START_SCREEN.previewRenderer = previewRenderer;
  START_SCREEN.previewRig = previewRig;

  applyPlayerAppearance();
  resizeStartScreenPreview();
}

function attemptStartScreenMusic() {
  if (START_SCREEN.musicStarted || START_SCREEN.musicDisabled || !START_SCREEN.music) return;

  const requestId = ++START_SCREEN.musicRequestId;

  START_SCREEN.music.play()
    .then(() => {
      if (START_SCREEN.musicDisabled || requestId !== START_SCREEN.musicRequestId) {
        START_SCREEN.music.pause();
        START_SCREEN.music.currentTime = 0;
        return;
      }
      START_SCREEN.musicStarted = true;
      START_SCREEN.musicUnlocked = true;
    })
    .catch(() => {
      if (requestId !== START_SCREEN.musicRequestId) return;
      START_SCREEN.musicStarted = false;
    });
}

function initStartScreenMusic() {
  if (START_SCREEN.music) return;

  const music = new Audio(START_SCREEN_CFG.musicPath);
  music.loop = true;
  music.preload = 'auto';
  music.volume = 0.45;
  START_SCREEN.music = music;

  const unlock = () => {
    attemptStartScreenMusic();
    if (START_SCREEN.musicUnlocked) {
      document.removeEventListener('pointerdown', unlock);
      document.removeEventListener('keydown', unlock);
      document.removeEventListener('touchstart', unlock);
    }
  };

  document.addEventListener('pointerdown', unlock);
  document.addEventListener('keydown', unlock);
  document.addEventListener('touchstart', unlock);
}

function stopStartScreenMusic() {
  START_SCREEN.musicDisabled = true;
  START_SCREEN.musicRequestId++;
  if (!START_SCREEN.music) return;
  START_SCREEN.music.pause();
  START_SCREEN.music.currentTime = 0;
  START_SCREEN.musicStarted = false;
}

function initStartScreen() {
  if (START_SCREEN.initialized) return;
  START_SCREEN.initialized = true;
  bindAppearanceControls();
  initStartScreenPreview();
  bindStartScreenPointer();
  initStartScreenMusic();
}

function updateStartScreen(dt) {
  if (!START_SCREEN.previewRig || !loaderEl || loaderEl.style.display === 'none') return;

  START_SCREEN.previewTime += dt;
  const t = START_SCREEN.previewTime;
  const rig = START_SCREEN.previewRig;
  const jumpHz = START_SCREEN_ANIM.jumpsPerMinute / 60;
  const jumpPhase = t * Math.PI * 2 * jumpHz;
  const bounceWave = Math.sin(jumpPhase);
  const hop = Math.max(0, bounceWave);
  const crouch = Math.max(0, -bounceWave);
  const sway = Math.sin(jumpPhase * 0.5);
  const twist = Math.sin(jumpPhase * 0.32);
  const armSwing = Math.sin(jumpPhase + 0.45);
  const legSwing = Math.sin(jumpPhase + Math.PI * 0.5);
  START_SCREEN.pointerX += (START_SCREEN.pointerTargetX - START_SCREEN.pointerX) * Math.min(1, START_SCREEN_ANIM.pointerFollow * dt);
  START_SCREEN.pointerY += (START_SCREEN.pointerTargetY - START_SCREEN.pointerY) * Math.min(1, START_SCREEN_ANIM.pointerFollow * dt);
  START_SCREEN.bodyLookX += (START_SCREEN.pointerX - START_SCREEN.bodyLookX) * Math.min(1, START_SCREEN_ANIM.pointerFollow * 0.6 * dt);
  START_SCREEN.bodyLookY += (START_SCREEN.pointerY - START_SCREEN.bodyLookY) * Math.min(1, START_SCREEN_ANIM.pointerFollow * 0.6 * dt);
  const pointerYaw = START_SCREEN.bodyLookX * START_SCREEN_ANIM.pointerBodyYaw;
  const pointerHeadYaw = START_SCREEN.pointerX * START_SCREEN_ANIM.pointerHeadYaw;
  const pointerPitch = START_SCREEN.pointerY * START_SCREEN_ANIM.pointerPitch;

  rig.group.rotation.y = START_SCREEN_ANIM.baseYaw + twist * START_SCREEN_ANIM.yawSwing + pointerYaw;
  rig.group.position.y = 0.12 + hop * START_SCREEN_ANIM.hopHeight;

  START_SCREEN.previewCamera.position.x = START_SCREEN.pointerX * START_SCREEN_ANIM.pointerCameraX;
  START_SCREEN.previewCamera.position.y = 0.85 - START_SCREEN.pointerY * START_SCREEN_ANIM.pointerCameraY;
  START_SCREEN.previewCamera.lookAt(START_SCREEN.bodyLookX * 0.08, 0.95 - pointerPitch * 0.18, 0);

  rig.upperBody.position.y = ANIM_CFG.upperBodyY + hop * START_SCREEN_ANIM.bodyBob - crouch * 0.022;
  rig.headGroup.position.y = ANIM_CFG.headY + hop * START_SCREEN_ANIM.headBob - crouch * 0.014;
  rig.upperBody.rotation.x = 0.1 + crouch * 0.2 - hop * 0.04 - START_SCREEN.bodyLookY * 0.16;
  rig.upperBody.rotation.y = sway * 0.08 + pointerYaw * 0.52;
  rig.upperBody.rotation.z = Math.sin(jumpPhase * 0.75) * 0.06;
  rig.headGroup.rotation.y = pointerHeadYaw * 0.68;
  rig.headGroup.rotation.z = -Math.sin(jumpPhase * 0.75) * 0.04;
  rig.headGroup.rotation.x = 0.03 + crouch * 0.04 - hop * 0.015 - START_SCREEN.pointerY * 0.2;

  rig.armPivotL.rotation.x = -0.12 + armSwing * 0.34 + hop * 0.12;
  rig.armPivotR.rotation.x = -0.08 - armSwing * 0.34 + hop * 0.12;
  rig.armPivotL.rotation.z = 0.14 + sway * 0.05;
  rig.armPivotR.rotation.z = -0.14 - sway * 0.05;

  rig.legPivotL.rotation.x = -0.14 + legSwing * 0.08 - crouch * 0.1;
  rig.legPivotR.rotation.x = -0.14 - legSwing * 0.08 - crouch * 0.1;
  rig.kneePivotL.rotation.x = 0.3 + crouch * 0.16 + hop * 0.04;
  rig.kneePivotR.rotation.x = 0.3 + crouch * 0.16 + hop * 0.04;
  rig.anklePivotL.rotation.x = -0.05 - rig.legPivotL.rotation.x * 0.74;
  rig.anklePivotR.rotation.x = -0.05 - rig.legPivotR.rotation.x * 0.74;

  rig.legPivotL.position.x = -0.08 + Math.sin(jumpPhase * 0.9) * 0.005;
  rig.legPivotR.position.x = 0.08 - Math.sin(jumpPhase * 0.9) * 0.005;

  START_SCREEN.previewRenderer.render(START_SCREEN.previewScene, START_SCREEN.previewCamera);
}


/* ── HUD & Fullscreen ── */

const hud = document.getElementById('hud');
const btnFs = document.getElementById('btn-fs');
const wrap = document.getElementById('wrap');

btnFs.addEventListener('click', () => {
  if (!document.fullscreenElement) {
    (wrap.requestFullscreen || wrap.webkitRequestFullscreen || wrap.mozRequestFullScreen).call(wrap);
  } else {
    (document.exitFullscreen || document.webkitExitFullscreen || document.mozCancelFullScreen).call(document);
  }
});

document.addEventListener('fullscreenchange', () => {
  btnFs.textContent = document.fullscreenElement ? '✕ Вийти' : '⛶ На весь екран';
  setTimeout(onResize, 100);
});

function updateHud() {
  hud.textContent = `pos: ${pl.x.toFixed(1)}, ${pl.y.toFixed(1)}  zoom: ${cam.zoom.toFixed(2)}x`;
}


/* ── Resize ── */

function onResize() {
  const w = window.innerWidth, h = window.innerHeight;
  aspect = w / h;
  cam.left = -frustum * aspect;
  cam.right = frustum * aspect;
  cam.top = frustum;
  cam.bottom = -frustum;
  cam.updateProjectionMatrix();
  renderer.setSize(w, h);
  if (typeof resizeStartScreenPreview === 'function') resizeStartScreenPreview();
}
window.addEventListener('resize', onResize);

/* ── Loading Screen ── */

const loaderEl = document.getElementById('loader');
const loaderBtn = document.getElementById('loader-play');
const loaderText = document.querySelector('.loader-text');
const loaderFill = document.querySelector('.loader-fill');
const loaderName = document.querySelector('.loader-name');
const playerNameInput = document.getElementById('player-name');
const bootstrap = window.ISOMANIA_BOOTSTRAP || {};
let playerName = localStorage.getItem(CONFIG.ui.playerNameStorageKey) || '';

function notifyGameJoin(name) {
  if (!bootstrap.notifyUrl || !bootstrap.gameToken) return;

  fetch(bootstrap.notifyUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Game-Token': bootstrap.gameToken,
    },
    body: JSON.stringify({ name }),
    keepalive: true,
  }).catch(() => {
    // Notification failures should not block game start.
  });
}

function showPlayButton() {
  loaderText.style.display = 'none';
  loaderFill.style.animation = 'none';
  loaderFill.style.width = '100%';
  loaderFill.style.marginLeft = '0';
  loaderName.style.display = 'block';
  loaderBtn.style.display = 'inline-flex';
  if (playerName) {
    playerNameInput.value = playerName;
    loaderBtn.disabled = false;
  } else {
    loaderBtn.disabled = true;
    loaderBtn.classList.add('disabled');
  }
  playerNameInput.focus();
}

// Enable play button only when name is entered
playerNameInput.addEventListener('input', () => {
  const hasName = playerNameInput.value.trim().length > 0;
  loaderBtn.disabled = !hasName;
  loaderBtn.classList.toggle('disabled', !hasName);
});

function hideLoader() {
  loaderEl.style.opacity = '0';
  setTimeout(() => { loaderEl.style.display = 'none'; }, 400);
}

/* ── Game Loop ── */

let prev = performance.now();
let gameStarted = false;

function loop(ts) {
  const dt = Math.min((ts - prev) / 1000, 0.05);
  prev = ts;
  if (gameStarted) {
    update(dt);
    updateAudio(dt);
  }
  if (typeof updateStartScreen === 'function') updateStartScreen(dt);
  updateCamera();
  renderer.render(scene, cam);
  updateHud();
  requestAnimationFrame(loop);
}

// Scene is ready — show play button
if (typeof initStartScreen === 'function') initStartScreen();
showPlayButton();

// Render scene in background while waiting
requestAnimationFrame(loop);

// Start game on click
loaderBtn.addEventListener('click', () => {
  if (!playerNameInput.value.trim()) return;
  playerName = playerNameInput.value.trim();
  localStorage.setItem(CONFIG.ui.playerNameStorageKey, playerName);
  notifyGameJoin(playerName);
  if (typeof stopStartScreenMusic === 'function') stopStartScreenMusic();
  unlockAudio().finally(() => {
    resetFootstepTracking();
  });
  clearKeys();
  gameStarted = true;
  prev = performance.now();
  hideLoader();
});

// Enter key in name input triggers play
playerNameInput.addEventListener('keydown', e => {
  if (e.key === 'Enter' && playerNameInput.value.trim()) {
    loaderBtn.click();
  }
});


